  49→function filterSections(sections: SectionData[], query: string): SectionData[] {
  50→  if (!query) return sections;
  51→  const lower = query.toLowerCase();
  52→  return sections
  53→    .map(section => ({
  54→      ...section,
  55→      items: section.items.filter(
  56→        item =>
  57→          item.title.toLowerCase().includes(lower) ||
  58→          item.subtitle?.toLowerCase().includes(lower),
  59→      ),
  60→    }))
  61→    .filter(section => section.items.length > 0);
  62→}
  63→
  64→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  65→  if (!query) return colors;
  66→  const lower = query.toLowerCase();
  67→  return colors.filter(
  68→    c =>
  69→      c.title.toLowerCase().includes(lower) ||
  70→      c.subtitle?.toLowerCase().includes(lower),
  71→  );
  72→}
  73→
  74→function flattenItems(sections: SectionData[]): ListItemData[] {
  75→  return sections.flatMap(s => s.items);
  76→}
  77→
  78→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  79→  switch (entry.type) {
  80→    case 'label':
  81→      return (
  82→        <DetailMetadata.Label
  83→          key={index}
  84→          title={entry.title}
  85→          text={entry.text}
  86→        />
  87→      );
  88→    case 'link':
  89→      return (
  90→        <DetailMetadata.Link
  91→          key={index}
  92→          title={entry.title}
  93→          text={entry.text}
  94→          target={entry.target}
  95→        />
  96→      );
  97→    case 'tag-list':
  98→      return (
  99→        <DetailMetadata.TagList key={index} title={entry.title}>
 100→          {entry.tags.map(tag => (
 101→            <DetailMetadata.Tag
 102→              key={tag.text}
 103→              text={tag.text}
 104→              color={tag.color}
 105→            />
 106→          ))}
 107→        </DetailMetadata.TagList>
 108→      );
 109→    case 'separator':
 110→      return <DetailMetadata.Separator key={index} />;
 111→  }
 112→}
