 260→function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
 261→  const [snippetForm, setSnippetForm] =
 262→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
 263→  const [formErrors, setFormErrors] = useState<
 264→    Partial<Record<keyof SnippetFormState, string>>
 265→  >({});
 266→
 267→  const handleSubmit = useCallback(() => {
 268→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
 269→    if (!snippetForm.name.trim()) {
 270→      errors.name = 'Name is required';
 271→    }
 272→    if (!snippetForm.snippet.trim()) {
 273→      errors.snippet = 'Snippet content is required';
 274→    }
 275→    setFormErrors(errors);
 276→    if (Object.keys(errors).length > 0) {
 277→      return;
 278→    }
 279→    onSubmit(snippetForm);
 280→  }, [
 281→    snippetForm,
 282→    onSubmit,
 283→  ]);
 284→
 285→  useKeyboardShortcut(
 286→    {
 287→      key: 'Enter',
 288→      meta: true,
 289→    },
 290→    handleSubmit,
 291→  );
 292→
 293→  return (
 294→    <Form onSubmit={handleSubmit}>
 295→      <FormTextField
 296→        label="Name"
 297→        value={snippetForm.name}
 298→        onChange={v =>
 299→          setSnippetForm(prev => ({
 300→            ...prev,
 301→            name: v,
 302→          }))
 303→        }
 304→        placeholder="e.g. Email Signature"
 305→        error={formErrors.name}
 306→        autoFocus
 307→      />
 308→      <FormTextField
 309→        label="Keyword"
 310→        value={snippetForm.keyword}
 311→        onChange={v =>
 312→          setSnippetForm(prev => ({
 313→            ...prev,
 314→            keyword: v,
 315→          }))
 316→        }
 317→        placeholder="e.g. !sig"
 318→        description="Type this to expand the snippet"
 319→      />
 320→      <FormDropdown
 321→        label="Category"
 322→        value={snippetForm.category}
 323→        onChange={v =>
 324→          setSnippetForm(prev => ({
 325→            ...prev,
 326→            category: v,
 327→          }))
 328→        }
 329→        options={SNIPPET_CATEGORIES}
 330→        placeholder="Select a category"
 331→      />
 332→      <FormTagPicker
 333→        label="Tags"
 334→        value={snippetForm.tags}
 335→        onChange={v =>
 336→          setSnippetForm(prev => ({
 337→            ...prev,
 338→            tags: v,
 339→          }))
 340→        }
 341→        options={SNIPPET_TAGS}
 342→        placeholder="Add tags..."
 343→        description="Categorize your snippet with tags"
 344→      />
 345→      <FormTextArea
 346→        label="Snippet"
 347→        value={snippetForm.snippet}
 348→        onChange={v =>
 349→          setSnippetForm(prev => ({
 350→            ...prev,
 351→            snippet: v,
 352→          }))
 353→        }
 354→        placeholder="Enter your snippet content..."
 355→        error={formErrors.snippet}
 356→        rows={5}
 357→      />
 358→      <FormCheckbox
 359→        label="Share with team"
 360→        checked={snippetForm.isShared}
 361→        onChange={v =>
 362→          setSnippetForm(prev => ({
 363→            ...prev,
 364→            isShared: v,
 365→          }))
 366→        }
 367→        description="Make this snippet available to your team members"
 368→      />
 369→      <FormDatePicker
 370→        label="Expires"
 371→        value={snippetForm.expiresAt}
 372→        onChange={v =>
 373→          setSnippetForm(prev => ({
 374→            ...prev,
 375→            expiresAt: v,
 376→          }))
 377→        }
 378→        description="Optional expiration date"
 379→      />
 380→    </Form>
 381→  );
 382→}
